            return ['error' => 'URL is required.', 'feed' => null, 'items' => []];
        }

        $timeout = isset($timeout) ? max(1, min(30, (int)$timeout)) : 15;
        $max_items = isset($max_items) ? max(1, min(100, (int)$max_items)) : 20;
        $body_limit = isset($body_limit) ? max(1024, min(5242880, (int)$body_limit)) : 524288;

        // Fetch the feed using PHP streams directly (same pattern as http_fetch)
        $ctx_opts = [
            'http' => [
