            ],
            'ssl' => [
                'verify_peer' => true,
                'verify_peer_name' => true,
                'allow_self_signed' => false,
            ],
        ];

        $context = stream_context_create($ctx_opts);

        $error_msg = null;
        set_error_handler(function ($severity, $message) use (&$error_msg) {
            $error_msg = $message;
            return true;
        });

        $xml_raw = @file_get_contents($url, false, $context);
        $http_response_header = $http_response_header ?? [];

        restore_error_handler();

        if ($xml_raw === false) {
            $reason = $error_msg ?? 'Failed to fetch feed.';
            if (preg_match('/Failed to open stream: (.+)$/', $reason, $m)) {
                $reason = trim($m[1]);
            }
            return ['error' => $reason, 'feed' => null, 'items' => []];
        }

        // Parse status code
        $status_code = 0;
        foreach ($http_response_header as $i => $line) {
            if ($i === 0 && preg_match('#HTTP/\d+\.\d+ (\d+)#', $line, $m)) {
                $status_code = (int)$m[1];
                break;
            }
        }

        if ($status_code >= 400) {
            return ['error' => "HTTP $status_code error fetching feed.", 'feed' => null, 'items' => []];
        }

        // Truncate extremely large XML
        if (strlen($xml_raw) > $body_limit) {
            $xml_raw = substr($xml_raw, 0, $body_limit);
        }

        // Suppress XML errors
        libxml_use_internal_errors(true);
        $xml = simplexml_load_string($xml_raw);
        $xml_errors = libxml_get_errors();
        libxml_clear_errors();

